import type { InputStream } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';

const { BACKSLASH } = characterCodes;

/**
 * Check whether the current char code is escaped.
 * @internal
 */
export function isEscaped(
  inputStream: InputStream,
  offset: number = 0,
): boolean {
  let backslashes = 0;
  let peekOffset = offset - 1;

  while (inputStream.peek(peekOffset) === BACKSLASH) {
    backslashes += 1;
    peekOffset -= 1;
  }

  return backslashes % 2 === 1;
}
